} as const;

export const UNIT_LABELS = {
  C: "°C",
  F: "°F",
} as const;

export const DEFAULT_UNIT = "C" as const;

export const STAT_LABELS = {
  HUMIDITY_SUFFIX: "%",
  WIND_SPEED_UNIT: "km/h",
} as const;


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, UseWeatherReturn } from './types';

export function useWeather(props: WeatherCardProps): UseWeatherReturn {
  const { temperature, humidity, windSpeed, condition, unit = 'C' } = props;

  return useMemo(() => {
    const formattedTemp = `${temperature}°${unit}`;
    const formattedHumidity = `${humidity}%`;

    const windUnit = unit === 'C' ? 'km/h' : 'mph';
    const formattedWind = `${windSpeed} ${windUnit}`;

    const iconMap: Record<string, string> = {
      sunny: '☀️',
      cloudy: '☁️',
      rainy: '🌧️',
      snowy: '❄️',
      thunderstorm: '⛈️',
    };

    const conditionIcon = iconMap[condition.toLowerCase()] || '☁️';

    return {
      formattedTemp,
      formattedHumidity,
      formattedWind,
      conditionIcon,
      tempUnit: unit,
    };
  }, [temperature, humidity, windSpeed, condition, unit]);
}


